mapper.select:
SELECT A.ID, A.STACK_CODE, A.STACK_NAME, A.POSITION, A.POSITION_FROM, A.POSITION_TIME, A.CREATE_BY, A.CREATE_TIME, A.UPDATE_BY, A.UPDATE_TIME, A.STACK_ID, A.DEL_FLAG, A.FREEHAND_SKETCHING, B.USER_NAME CREATE_BY_NAME FROM M_STORAGE_STACK_POSITION A LEFT JOIN SYS_USER B ON B.ID = A.CREATE_BY
AND A.STACK_ID = #{stackId}
ORDER BY A.STACK_ID, A.CREATE_TIME DESC
